const lead = $input.first().json;

let score = 0;
const factors = [];

// Source quality
const source = (lead.source || '').toLowerCase();
if (source === 'referral') { score += 30; factors.push('Referral source (+30)'); }
else if (source === 'organic' || source === 'seo') { score += 25; factors.push('Organic source (+25)'); }
else if (source.includes('paid') || source.includes('google_ads') || source.includes('ppc') || source.includes('lsa')) { score += 20; factors.push('Paid source (+20)'); }
else if (source === 'manual') { score += 15; factors.push('Manual entry (+15)'); }
else { score += 10; factors.push('Other source (+10)'); }

// Contact completeness
if (lead.phone) { score += 5; factors.push('Has phone (+5)'); }
if (lead.email) { score += 5; factors.push('Has email (+5)'); }
if (lead.address) { score += 5; factors.push('Has address (+5)'); }

// High-value service detection
const service = (lead.service || '').toLowerCase();
const highValueServices = ['hardscaping', 'commercial', 'patio', 'retaining wall', 'landscape design', 'irrigation', 'outdoor kitchen'];
const midValueServices = ['fertilization', 'aeration', 'overseeding', 'mowing', 'lawn care', 'lawn maintenance'];
const cleanupServices = ['cleanup', 'leaf', 'mulch', 'gutter', 'snow'];
if (highValueServices.some(s => service.includes(s))) {
  score += 20; factors.push('High-value service (+20)');
} else if (midValueServices.some(s => service.includes(s))) {
  score += 10; factors.push('Mid-value service (+10)');
} else if (cleanupServices.some(s => service.includes(s))) {
  score += 5; factors.push('Cleanup service (+5)');
}

// Core service area detection
const address = (lead.address || '').toLowerCase();
const coreAreas = ['madison', 'middleton', 'fitchburg', 'verona', 'waunakee', 'deforest', 'sun prairie', 'stoughton', 'monona', 'mcfarland'];
if (coreAreas.some(a => address.includes(a))) {
  score += 5; factors.push('Core service area (+5)');
}

const finalScore = Math.min(score, 100);

let lead_tier = 'cold';
if (finalScore >= 70) lead_tier = 'hot';
else if (finalScore >= 50) lead_tier = 'warm';
else if (finalScore >= 30) lead_tier = 'standard';

return {
  json: {
    ...lead,
    lead_score: finalScore,
    lead_tier: lead_tier,
    score_factors: factors
  }
};

